function App() {
  return (
    <div
      style={{
        backgroundColor: "#121212",
        color: "white",
        minHeight: "100vh",
        padding: "20px",
      }}
    >
      <h1>🎵 AI Music App</h1>

      <h2>Trending Songs</h2>

      <div style={{ display: "flex", gap: "20px" }}>
        <div
          style={{
            background: "#282828",
            padding: "20px",
            borderRadius: "10px",
          }}
        >
          <h3>Song 1</h3>
          <p>Artist 1</p>
        </div>

        <div
          style={{
            background: "#282828",
            padding: "20px",
            borderRadius: "10px",
          }}
        >
          <h3>Song 2</h3>
          <p>Artist 2</p>
        </div>

        <div
          style={{
            background: "#282828",
            padding: "20px",
            borderRadius: "10px",
          }}
        >
          <h3>Song 3</h3>
          <p>Artist 3</p>
        </div>
      </div>
    </div>
  );
}

export default App;
